### Registering Client-Side Markdown Transformer in PayloadCMS Lexical

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/custom-features.mdx

This TypeScript example demonstrates how to create and register a custom markdown transformer for a client-side Lexical feature in PayloadCMS. It defines an `ElementTransformer` that listens for the `+++` pattern to create a new `MyNode`, integrating it into a `createClientFeature` call to extend editor functionality.

```ts
import { createClientFeature } from '@payloadcms/richtext-lexical/client'
import type { ElementTransformer } from '@payloadcms/richtext-lexical/lexical/markdown'
import { $createMyNode, $isMyNode, MyNode } from './nodes/MyNode'

const MyMarkdownTransformer: ElementTransformer = {
  type: 'element',
  dependencies: [MyNode],
  export: (node, exportChildren) => {
    if (!$isMyNode(node)) {
      return null
    }
    return '+++'
  },
  // match ---
  regExp: /^+++s*$/,
  replace: (parentNode) => {
    const node = $createMyNode()
    if (node) {
      parentNode.replace(node)
    }
  },
}

export const MyFeature = createClientFeature({
  markdownTransformers: [MyMarkdownTransformer],
})
```

